How to store objects in HTML5 localStorage/sessionStorage

```
var testObject = { 'one': 1, 'two': 2, 'three': 3 };
console.log('typeof testObject: ' + typeof testObject);
console.log('testObject properties:');
for (var prop in testObject) {
    console.log('  ' + prop + ': ' + testObject[prop]);
}
// Put the object into storage
localStorage.setItem('testObject', testObject);
```

Using async/await with a forEach loop

```
import fs from 'fs-promise'
async function printFiles () {
  const files = await getFilePaths() // Assume this works fine
  files.forEach(async (file) => {
    const contents = await fs.readFile(file, 'utf8')
    console.log(contents)
  })
}
```

So this is a mineflayer function, the bot will keep 64 cooked pork chop and all of the leather, and else it will throw alway and the extra cooked pork chop will be also thrown away, but this code, the bot throw all of the cooked pork chop, can you fix: async function throwItems() {
 const itemsToThrow = bot.inventory.items().filter(item => {
 const itemId = item.type;
 if (itemId !== porkchopId && !item.name.toLowerCase().includes('leather')) {
 return true;
 }
 return false;
 });
 const goal = new GoalNear(5114880, 134, 5096970, 2);
 await bot.pathfinder.goto(goal);
 for (const item of itemsToThrow) {
 await bot.tossStack(item);
 }
 handlePorkChops();
 }
 async function handlePorkChops() {
 const porkchopId = bot.registry.itemsByName.cooked_porkchop.id;
 const porkChops = bot.inventory.items().filter(item => item.type === porkchopId);

 const numToKeep = 64;
 while (porkChops.length > numToKeep) { 
 await bot.tossStack(porkChops.pop()); 
 } 
 dig1()
 }
